     1→/**
     2→ * @module RuntimeEvents
     3→ *
     4→ * Strongly typed event definitions emitted by a `ConversationRuntime`.
     5→ *
     6→ * ## Ownership
     7→ * Events are produced by `ConversationRuntime` and consumed by the surrounding
     8→ * orchestration layer (call coordinator, monitoring, analytics). No module
     9→ * inside the runtime consumes its own events.
    10→ *
    11→ * ## Thread Safety
    12→ * Events are value objects — immutable once constructed. Safe to pass across
    13→ * async boundaries without copying.
    14→ *
    15→ * ## Lifecycle
    16→ * Events are emitted in strict chronological order within a single runtime
    17→ * instance. Subscribers must not mutate the event payload.
    18→ */
    19→
    20→import type { Timestamp, SessionId, CallSid } from '../types/index.js';
    21→import type { RuntimeState } from './RuntimeState.js';
    22→
    23→/**
    24→ * Common fields carried by every runtime event.
    25→ */
    26→interface BaseRuntimeEvent {
    27→  /** Millisecond Unix timestamp of when the event was created. */
    28→  readonly timestamp: Timestamp;
    29→  /** The session this runtime is managing. */
    30→  readonly sessionId: SessionId;
    31→  /** The telephony call identifier bound to this runtime. */
    32→  readonly callSid: CallSid;
    33→}
    34→
    35→/**
    36→ * Emitted immediately after a `ConversationRuntime` instance is constructed
    37→ * and enters the CREATED state.
    38→ */
    39→export interface RuntimeCreatedEvent extends BaseRuntimeEvent {
    40→  readonly type: 'runtime.created';
    41→  readonly campaignId: string;
    42→}
    43→
    44→/**
    45→ * Emitted when the transport is fully established and the runtime enters
    46→ * the CONNECTED state, ready to start the conversation.
    47→ */
    48→export interface RuntimeConnectedEvent extends BaseRuntimeEvent {
    49→  readonly type: 'runtime.connected';
    50→  readonly transportProtocol: string;
    51→}
    52→
    53→/**
    54→ * Emitted each time the runtime enters the LISTENING state and begins
    55→ * capturing caller audio via STT.
    56→ */
    57→export interface RuntimeListeningEvent extends BaseRuntimeEvent {
    58→  readonly type: 'runtime.listening';
    59→  /** Zero-based index of the current conversational turn. */
    60→  readonly turnIndex: number;
    61→}
    62→
    63→/**
    64→ * Emitted when the runtime enters the THINKING state.
    65→ * The caller's utterance has been transcribed and the LLM request is in-flight.
    66→ */
    67→export interface RuntimeThinkingEvent extends BaseRuntimeEvent {
    68→  readonly type: 'runtime.thinking';
    69→  readonly turnIndex: number;
    70→  /** The final transcript that triggered this thinking phase. */
    71→  readonly transcript: string;
    72→  /** Milliseconds elapsed from utterance end to LLM request dispatch. */
    73→  readonly sttLatencyMs: number;
    74→}
    75→
    76→/**
    77→ * Emitted when the runtime enters the SPEAKING state.
    78→ * TTS audio is now streaming to the caller.
    79→ */
    80→export interface RuntimeSpeakingEvent extends BaseRuntimeEvent {
    81→  readonly type: 'runtime.speaking';
    82→  readonly turnIndex: number;
    83→  /** Character count of the text being synthesised. */
    84→  readonly textLength: number;
    85→  /** The voice identifier used for synthesis. */
    86→  readonly voice: string;
    87→  /** Milliseconds elapsed from LLM response completion to TTS stream start. */
    88→  readonly ttsLatencyMs: number;
    89→}
    90→
    91→/**
    92→ * Emitted when the caller speaks while the runtime is in SPEAKING state,
    93→ * triggering a barge-in and entering the INTERRUPTED state.
    94→ */
    95→export interface RuntimeInterruptedEvent extends BaseRuntimeEvent {
    96→  readonly type: 'runtime.interrupted';
    97→  readonly turnIndex: number;
    98→  /** Milliseconds into the TTS stream at which the interruption occurred. */
    99→  readonly interruptedAtMs: number;
   100→}
   101→
   102→/**
   103→ * Emitted when the conversation ends gracefully and the runtime enters
   104→ * the COMPLETED state.
   105→ */
   106→export interface RuntimeCompletedEvent extends BaseRuntimeEvent {
   107→  readonly type: 'runtime.completed';
   108→  /** Total number of completed conversational turns. */
   109→  readonly totalTurns: number;
   110→  /** Total wall-clock duration of the conversation in milliseconds. */
   111→  readonly durationMs: number;
   112→  /** Human-readable reason for completion (e.g. "goal_reached", "max_turns"). */
   113→  readonly completionReason: string;
   114→}
   115→
   116→/**
   117→ * Emitted when the runtime enters the CLOSED state and all resources
   118→ * have been released.
   119→ */
   120→export interface RuntimeClosedEvent extends BaseRuntimeEvent {
   121→  readonly type: 'runtime.closed';
   122→  /** The state the runtime was in immediately before closing. */
   123→  readonly closedFromState: RuntimeState;
   124→}
   125→
   126→/**
   127→ * Emitted when the runtime encounters an unrecoverable error and enters
   128→ * the FAILED state.
   129→ */
   130→export interface RuntimeErrorEvent extends BaseRuntimeEvent {
   131→  readonly type: 'runtime.error';
   132→  readonly errorCode: string;
   133→  readonly errorMessage: string;
   134→  /** The state the runtime occupied when the error occurred. */
   135→  readonly failedInState: RuntimeState;
   136→  /** Whether the error originated in a provider (STT/LLM/TTS/telephony). */
   137→  readonly providerError: boolean;
   138→}
   139→
   140→/**
   141→ * Discriminated union of all events emitted by a `ConversationRuntime`.
   142→ */
   143→export type RuntimeEvent =
   144→  | RuntimeCreatedEvent
   145→  | RuntimeConnectedEvent
   146→  | RuntimeListeningEvent
   147→  | RuntimeThinkingEvent
   148→  | RuntimeSpeakingEvent
   149→  | RuntimeInterruptedEvent
   150→  | RuntimeCompletedEvent
   151→  | RuntimeClosedEvent
   152→  | RuntimeErrorEvent;
   153→
   154→/** Maps each event type literal to its concrete event interface. */
   155→export type RuntimeEventMap = {
   156→  [E in RuntimeEvent as E['type']]: E;
   157→};
   158→
   159→export type RuntimeEventType = RuntimeEvent['type'];
   160→export type RuntimeEventHandler<T extends RuntimeEvent = RuntimeEvent> = (event: T) => void;
