     1→/**
     2→ * @module AudioEngine
     3→ *
     4→ * The top-level coordinator for all audio processing in Voice Engine V2.
     5→ *
     6→ * ## Purpose
     7→ * `AudioEngine` is the single entry point for all audio I/O within a live
     8→ * call. It owns the inbound and outbound pipelines, the shared clock, and
     9→ * all quality metrics. Downstream consumers (the orchestrator) deliver chunks
    10→ * via `ingestInbound()` and pull processed outbound chunks via
    11→ * `tickOutbound()`.
    12→ *
    13→ * It contains NO WebSocket, NO HTTP, NO transport, NO provider, and NO
    14→ * codec implementation. All codec concerns are limited to descriptors in
    15→ * `AudioCodec.ts`; all timing is routed through `IAudioClock`.
    16→ *
    17→ * ## Ownership
    18→ * Created by `AudioEngineFactory` once per live call. Destroyed by calling
    19→ * `destroy()` when the call ends.
    20→ *
    21→ * ## Thread Safety
    22→ * All methods are synchronous or return simple values. Must be driven
    23→ * sequentially from the orchestrator's async pipeline.
    24→ *
    25→ * ## Lifecycle
    26→ * ```
    27→ * createAudioEngine()
    28→ *   └─► start()           — resets clock epoch, marks engine active
    29→ *         ├─► ingestInbound(chunk)   — deliver caller audio into inbound pipeline
    30→ *         ├─► tickInbound()          — retrieve scheduling result for inbound audio
    31→ *         ├─► ingestOutbound(chunk)  — deliver response audio into outbound pipeline
    32→ *         ├─► tickOutbound()         — retrieve scheduling result for outbound audio
    33→ *         ├─► flushOutbound()        — immediate drain (barge-in)
    34→ *         └─► getSnapshot()          — read combined statistics
    35→ *   └─► stop()            — signals EOS on both pipelines
    36→ *   └─► destroy()         — clears all state; engine becomes unusable
    37→ * ```
    38→ */
    39→
    40→import type { Nullable } from '../types/index.js';
    41→import type { AudioChunk, AudioDirection } from './AudioChunk.js';
    42→import type { IAudioClock } from './AudioClock.js';
    43→import type { AudioSchedulerConfig } from './AudioScheduler.js';
    44→import type { AudioStatisticsSnapshot } from './AudioStatistics.js';
    45→import type { AudioLatencySnapshot } from './AudioLatency.js';
    46→import type { PipelineResult } from './AudioPipeline.js';
    47→import { AudioPipeline } from './AudioPipeline.js';
    48→import { AudioLatency } from './AudioLatency.js';
    49→import { AudioStatistics } from './AudioStatistics.js';
    50→import { VoiceEngineError, ErrorCode } from '../errors/index.js';
    51→
    52→/**
    53→ * Configuration for the `AudioEngine`.
    54→ */
    55→export interface AudioEngineConfig {
    56→  /**
    57→   * Scheduler configuration overrides for the inbound pipeline.
    58→   * Defaults to `DEFAULT_SCHEDULER_CONFIG`.
    59→   */
    60→  readonly inboundScheduler?: Partial<AudioSchedulerConfig>;
    61→
    62→  /**
    63→   * Scheduler configuration overrides for the outbound pipeline.
    64→   * Defaults to `DEFAULT_SCHEDULER_CONFIG`.
    65→   */
    66→  readonly outboundScheduler?: Partial<AudioSchedulerConfig>;
    67→
    68→  /**
    69→   * Rolling window size (in samples) for latency and jitter averaging.
    70→   * Defaults to 50.
    71→   */
    72→  readonly rollingWindowSize?: number;
    73→}
    74→
    75→/**
    76→ * A combined snapshot of the engine's runtime state.
    77→ */
    78→export interface AudioEngineSnapshot {
    79→  readonly isRunning: boolean;
    80→  readonly uptimeMs: number;
    81→  readonly statistics: AudioStatisticsSnapshot;
    82→  readonly latency: AudioLatencySnapshot;
    83→  readonly inboundBufferDepth: number;
    84→  readonly outboundBufferDepth: number;
    85→  readonly inboundBufferDurationMs: number;
    86→  readonly outboundBufferDurationMs: number;
    87→}
    88→
    89→/**
    90→ * Public interface for the audio engine.
    91→ */
    92→export interface IAudioEngine {
    93→  /** Whether the engine is currently running. */
    94→  readonly isRunning: boolean;
    95→
    96→  /** Starts the engine. Must be called before ingesting any chunks. */
    97→  start(): void;
    98→
    99→  /**
   100→   * Ingests a caller audio chunk into the inbound pipeline.
   101→   * Only valid while the engine is running.
   102→   */
   103→  ingestInbound(chunk: AudioChunk): void;
   104→
   105→  /**
   106→   * Produces a scheduling result for inbound audio.
   107→   * Call after one or more `ingestInbound()` calls.
   108→   */
   109→  tickInbound(playbackDebtMs?: Nullable<number>): PipelineResult;
   110→
   111→  /**
   112→   * Ingests a response audio chunk into the outbound pipeline.
   113→   * Only valid while the engine is running.
   114→   */
   115→  ingestOutbound(chunk: AudioChunk): void;
   116→
   117→  /**
   118→   * Produces a scheduling result for outbound audio.
   119→   * Call on each orchestrator tick to determine what to play to the caller.
   120→   */
   121→  tickOutbound(playbackDebtMs?: Nullable<number>): PipelineResult;
   122→
   123→  /**
   124→   * Records that the first outbound audio chunk has been played.
   125→   * Used to compute response and end-to-end latency.
   126→   *
   127→   * @param utteranceCommittedAt - When the caller's utterance was committed.
   128→   * @param firstChunkPlayedAt   - When the first outbound chunk was played.
   129→   */
   130→  recordResponseLatency(utteranceCommittedAt: number, firstChunkPlayedAt: number): void;
   131→
   132→  /**
   133→   * Requests an immediate flush of the outbound pipeline (e.g. barge-in).
   134→   */
   135→  flushOutbound(): PipelineResult;
   136→
   137→  /**
   138→   * Returns a combined snapshot of engine state and quality metrics.
   139→   */
   140→  getSnapshot(): Readonly<AudioEngineSnapshot>;
   141→
   142→  /**
   143→   * Signals end-of-stream on both pipelines.
   144→   * Pending chunks will be flushed on the next tick.
   145→   */
   146→  stop(): void;
   147→
   148→  /**
   149→   * Destroys the engine, releasing all state.
   150→   * Safe to call multiple times; subsequent calls are no-ops.
   151→   */
   152→  destroy(): void;
   153→}
   154→
   155→/**
   156→ * Production implementation of `IAudioEngine`.
   157→ */
   158→export class AudioEngine implements IAudioEngine {
   159→  private readonly _clock: IAudioClock;
   160→  private readonly _inbound: AudioPipeline;
   161→  private readonly _outbound: AudioPipeline;
   162→  private readonly _latency: AudioLatency;
   163→  private readonly _statistics: AudioStatistics;
   164→
   165→  private _running = false;
   166→  private _startedAt: Nullable<number> = null;
   167→  private _destroyed = false;
   168→
   169→  constructor(
   170→    clock: IAudioClock,
   171→    config: AudioEngineConfig = {}
   172→  ) {
   173→    this._clock = clock;
   174→    this._latency = new AudioLatency(config.rollingWindowSize ?? 50);
   175→    this._statistics = new AudioStatistics();
   176→
   177→    this._inbound = new AudioPipeline(
   178→      { direction: 'inbound', schedulerConfig: config.inboundScheduler },
   179→      this._clock,
   180→      this._latency,
   181→      this._statistics
   182→    );
   183→
   184→    this._outbound = new AudioPipeline(
   185→      { direction: 'outbound', schedulerConfig: config.outboundScheduler },
   186→      this._clock,
   187→      this._latency,
   188→      this._statistics
   189→    );
   190→  }
   191→
   192→  // ─── Lifecycle ────────────────────────────────────────────────────────────
   193→
   194→  get isRunning(): boolean {
   195→    return this._running;
   196→  }
   197→
   198→  start(): void {
   199→    this._assertNotDestroyed('start');
   200→    if (this._running) return;
   201→    this._clock.reset();
   202→    this._startedAt = this._clock.now();
   203→    this._running = true;
   204→  }
   205→
   206→  stop(): void {
   207→    if (!this._running || this._destroyed) return;
   208→    this._inbound.signalEndOfStream();
   209→    this._outbound.signalEndOfStream();
   210→    this._running = false;
   211→  }
   212→
   213→  destroy(): void {
   214→    if (this._destroyed) return;
   215→    this._running = false;
   216→    this._inbound.reset();
   217→    this._outbound.reset();
   218→    this._statistics.reset();
   219→    this._latency.reset();
   220→    this._destroyed = true;
   221→  }
   222→
   223→  // ─── Inbound Pipeline ────────────────────────────────────────────────────
   224→
   225→  ingestInbound(chunk: AudioChunk): void {
   226→    this._assertRunning('ingestInbound');
   227→    this._validateDirection(chunk.direction, 'inbound', 'ingestInbound');
   228→    this._inbound.ingest(chunk);
   229→  }
   230→
   231→  tickInbound(playbackDebtMs: Nullable<number> = null): PipelineResult {
   232→    this._assertNotDestroyed('tickInbound');
   233→    return this._inbound.tick(playbackDebtMs);
   234→  }
   235→
   236→  // ─── Outbound Pipeline ───────────────────────────────────────────────────
   237→
   238→  ingestOutbound(chunk: AudioChunk): void {
   239→    this._assertRunning('ingestOutbound');
   240→    this._validateDirection(chunk.direction, 'outbound', 'ingestOutbound');
   241→    this._outbound.ingest(chunk);
   242→  }
   243→
   244→  tickOutbound(playbackDebtMs: Nullable<number> = null): PipelineResult {
   245→    this._assertNotDestroyed('tickOutbound');
   246→    return this._outbound.tick(playbackDebtMs);
   247→  }
   248→
   249→  flushOutbound(): PipelineResult {
   250→    this._assertNotDestroyed('flushOutbound');
   251→    this._outbound.requestFlush();
   252→    return this._outbound.tick(null);
   253→  }
   254→
   255→  // ─── Latency Recording ───────────────────────────────────────────────────
   256→
   257→  recordResponseLatency(utteranceCommittedAt: number, firstChunkPlayedAt: number): void {
   258→    this._latency.recordResponse(utteranceCommittedAt, firstChunkPlayedAt);
   259→  }
   260→
   261→  // ─── Snapshot ─────────────────────────────────────────────────────────────
   262→
   263→  getSnapshot(): Readonly<AudioEngineSnapshot> {
   264→    return Object.freeze<AudioEngineSnapshot>({
   265→      isRunning: this._running,
   266→      uptimeMs: this._startedAt !== null ? this._clock.elapsed(this._startedAt) : 0,
   267→      statistics: this._statistics.snapshot(),
   268→      latency: this._latency.snapshot(),
   269→      inboundBufferDepth: this._inbound.bufferDepth,
   270→      outboundBufferDepth: this._outbound.bufferDepth,
   271→      inboundBufferDurationMs: this._inbound.bufferDurationMs,
   272→      outboundBufferDurationMs: this._outbound.bufferDurationMs,
   273→    });
   274→  }
   275→
   276→  // ─── Private Helpers ─────────────────────────────────────────────────────
   277→
   278→  private _assertRunning(method: string): void {
   279→    this._assertNotDestroyed(method);
   280→    if (!this._running) {
   281→      throw new VoiceEngineError(
   282→        `AudioEngine.${method}() called while engine is not running`,
   283→        ErrorCode.PIPELINE_ABORTED,
   284→        false
   285→      );
   286→    }
   287→  }
   288→
   289→  private _assertNotDestroyed(method: string): void {
   290→    if (this._destroyed) {
   291→      throw new VoiceEngineError(
   292→        `AudioEngine.${method}() called after destroy()`,
   293→        ErrorCode.PIPELINE_ABORTED,
   294→        false
   295→      );
   296→    }
   297→  }
   298→
   299→  private _validateDirection(
   300→    actual: AudioDirection,
   301→    expected: AudioDirection,
   302→    method: string
   303→  ): void {
   304→    if (actual !== expected) {
   305→      throw new VoiceEngineError(
   306→        `AudioEngine.${method}() received a '${actual}' chunk; expected '${expected}'`,
   307→        ErrorCode.AUDIO_DECODE_FAILED,
   308→        false,
   309→        { actual, expected }
   310→      );
   311→    }
   312→  }
   313→}
