    56→
    57→// ─── Realtime Session Abstraction ─────────────────────────────────────────────
    58→
    59→/**
    60→ * Abstract interface for a real-time AI provider session.
    61→ *
    62→ * Implemented by provider-specific sessions (e.g. `OpenAIRealtimeSession`).
    63→ * The orchestrator depends ONLY on this interface — no OpenAI SDK is imported here.
    64→ */
    65→export interface IRealtimeProviderSession {
    66→  /** Whether the session's connection is currently open. */
    67→  readonly isConnected: boolean;
    68→
    69→  /** Opens the session connection. Must be called before any send methods. */
    70→  connect(): Promise<void>;
    71→
    72→  /**
    73→   * Appends a base64-encoded audio chunk to the provider's input buffer.
    74→   * Fire-and-forget — does not await server acknowledgement.
    75→   */
    76→  sendAudio(base64Chunk: string): void;
    77→
    78→  /**
    79→   * Sends a text message into the conversation and triggers a response.
    80→   */
    81→  sendText(text: string): Promise<void>;
    82→
    83→  /**
    84→   * Cancels the current in-progress response (barge-in handling).
    85→   */
    86→  interrupt(): Promise<void>;
    87→
    88→  /**
    89→   * Updates the active system instructions without closing the session.
    90→   */
    91→  updateInstructions(instructions: string): Promise<void>;
    92→
    93→  /** Gracefully closes the session connection. */
    94→  close(): Promise<void>;
    95→
    96→  /** Registers a typed event handler on the session. */
    97→  on(type: string, handler: (event: unknown) => void): void;
    98→
    99→  /** Removes a previously registered event handler. */
   100→  off(type: string, handler: (event: unknown) => void): void;
   101→}
   102→
   103→// ─── Orchestrator State ───────────────────────────────────────────────────────
   104→
   105→/**
   106→ * Lifecycle states of the `ConversationOrchestrator` itself.
   107→ * Distinct from `TurnState` (per-turn) and `RuntimeState` (low-level).
   108→ */
   109→export enum OrchestratorState {
   110→  IDLE        = 'IDLE',
   111→  STARTING    = 'STARTING',
   112→  RUNNING     = 'RUNNING',
   113→  STOPPING    = 'STOPPING',
   114→  COMPLETED   = 'COMPLETED',
   115→  FAILED      = 'FAILED',
   116→  DESTROYED   = 'DESTROYED',
   117→}
   118→
   119→// ─── Orchestrator Events ──────────────────────────────────────────────────────
   120→
   121→export type OrchestratorEventType =
   122→  | 'orchestrator.started'
   123→  | 'orchestrator.turn_started'
   124→  | 'orchestrator.turn_completed'
   125→  | 'orchestrator.turn_failed'
   126→  | 'orchestrator.interrupted'
   127→  | 'orchestrator.completed'
   128→  | 'orchestrator.failed'
   129→  | 'orchestrator.destroyed';
   130→
   131→export interface OrchestratorEvent {
   132→  readonly type: OrchestratorEventType;
   133→  readonly timestamp: Timestamp;
   134→  readonly sessionId: SessionId;
   135→  readonly payload: Readonly<Record<string, unknown>>;
   136→}
   137→
   138→export type OrchestratorEventHandler = (event: OrchestratorEvent) => void;
   139→
   140→// ─── Orchestrator Interface ───────────────────────────────────────────────────
   141→
   142→/**
   143→ * Public contract for a single conversation orchestrator instance.
   144→ */
   145→export interface IConversationOrchestrator {
   146→  /** Current lifecycle state of the orchestrator. */
   147→  readonly state: OrchestratorState;
   148→
   149→  /**
   150→   * Initialises and connects all resources, then begins the first turn.
   151→   * Transitions: IDLE → STARTING → RUNNING.
   152→   *
   153→   * @throws {VoiceEngineError} if startup fails.
   154→   */
   155→  start(): Promise<void>;
   156→
   157→  /**
   158→   * Gracefully ends the conversation.
   159→   * Transitions: RUNNING → STOPPING → COMPLETED.
   160→   *
   161→   * @param reason - Human-readable reason for stopping.
   162→   */
   163→  stop(reason?: string): Promise<void>;
   164→
   165→  /**
   166→   * Delivers a base64-encoded audio chunk to the provider session.
   167→   * Only has effect while the orchestrator is RUNNING.
   168→   */
   169→  handleAudioChunk(base64Chunk: string, now: Timestamp): void;
   170→
   171→  /**
   172→   * Signals a barge-in. The orchestrator will cancel the current response
   173→   * and return to LISTENING if policy allows.
   174→   */
   175→  interrupt(now: Timestamp): Promise<void>;
   176→
   177→  /**
   178→   * Returns the current conversation context (read-only view).
   179→   */
   180→  getContext(): Readonly<ConversationContext>;
   181→
   182→  /** Subscribes to orchestrator lifecycle events. */
   183→  on(type: OrchestratorEventType, handler: OrchestratorEventHandler): void;
   184→
   185→  /** Unsubscribes from orchestrator lifecycle events. */
   186→  off(type: OrchestratorEventType, handler: OrchestratorEventHandler): void;
   187→
   188→  /**
   189→   * Forces an immediate teardown from any state.
   190→   * Safe to call multiple times; subsequent calls are no-ops.
   191→   */
   192→  destroy(): void;
   193→}
   194→
   195→// ─── Implementation ───────────────────────────────────────────────────────────
   196→
   197→/**
   198→ * Production implementation of `IConversationOrchestrator`.
   199→ */
   200→export class ConversationOrchestrator implements IConversationOrchestrator {
   201→  private readonly _runtime: ConversationRuntime;
   202→  private readonly _session: IRealtimeProviderSession;
   203→  private readonly _resolver: IProviderResolver;
   204→  private readonly _context: ConversationContext;
   205→  private readonly _interruptManager: InterruptManager;
   206→  private readonly _scheduler: TurnScheduler;
   207→  private readonly _policy: TurnPolicy;
   208→  private readonly _logger: ILogger;
   209→  private readonly _metrics: IMetricsCollector;
   210→  private readonly _clock: RuntimeContext['clock'];
   211→
   212→  private _state: OrchestratorState = OrchestratorState.IDLE;
   213→  private _turnIndex = 0;
   214→  private _nextTurnId = 1;
   215→
   216→  private readonly _handlers = new Map<OrchestratorEventType, Set<OrchestratorEventHandler>>();
   217→
   218→  constructor(deps: {
   219→    runtime: ConversationRuntime;
   220→    session: IRealtimeProviderSession;
   221→    resolver: IProviderResolver;
   222→    context: ConversationContext;
   223→    policy: TurnPolicy;
   224→    logger: ILogger;
   225→    metrics: IMetricsCollector;
   226→    clock: RuntimeContext['clock'];
   227→  }) {
   228→    this._runtime = deps.runtime;
   229→    this._session = deps.session;
   230→    this._resolver = deps.resolver;
   231→    this._context = deps.context;
   232→    this._policy = deps.policy;
   233→    this._logger = deps.logger.child({ component: 'ConversationOrchestrator', sessionId: deps.context.sessionId });
   234→    this._metrics = deps.metrics;
   235→    this._clock = deps.clock;
   236→    this._interruptManager = new InterruptManager(deps.policy);
   237→    this._scheduler = new TurnScheduler(deps.policy);
   238→  }
   239→
   240→  // ─── Public API ─────────────────────────────────────────────────────────
   241→
   242→  get state(): OrchestratorState {
   243→    return this._state;
   244→  }
   245→
   246→  async start(): Promise<void> {
   247→    this._assertState(OrchestratorState.IDLE, 'start');
   248→    this._setState(OrchestratorState.STARTING);
   249→    this._logger.info('ConversationOrchestrator starting');
   250→
   251→    try {
   252→      await this._runtime.initialize();
   253→      await this._runtime.connect();
   254→      await this._session.connect();
   255→      this._registerSessionHandlers();
   256→
   257→      this._setState(OrchestratorState.RUNNING);
   258→      this._emit('orchestrator.started', {});
   259→
   260→      await this._beginNextTurn();
   261→    } catch (err) {
   262→      this._setState(OrchestratorState.FAILED);
   263→      this._emit('orchestrator.failed', { reason: String(err) });
   264→      throw err;
   265→    }
   266→  }
   267→
   268→  async stop(reason: string = 'requested'): Promise<void> {
   269→    if (this._state !== OrchestratorState.RUNNING) return;
   270→    this._setState(OrchestratorState.STOPPING);
   271→    this._logger.info('ConversationOrchestrator stopping', { reason });
   272→
   273→    await this._runtime.complete(reason);
   274→    await this._session.close();
   275→    await this._runtime.close();
   276→
   277→    this._setState(OrchestratorState.COMPLETED);
   278→    this._emit('orchestrator.completed', { reason, totalTurns: this._context.completedTurnCount });
   279→  }
   280→
   281→  handleAudioChunk(base64Chunk: string, now: Timestamp): void {
   282→    if (this._state !== OrchestratorState.RUNNING) return;
   283→    this._context.touch(now);
   284→    this._session.sendAudio(base64Chunk);
   285→  }
   286→
   287→  async interrupt(now: Timestamp): Promise<void> {
   288→    if (this._state !== OrchestratorState.RUNNING) return;
   289→
   290→    const accepted = this._interruptManager.request(now);
   291→    if (!accepted) {
   292→      this._logger.debug('Interrupt request rejected by InterruptManager');
   293→      return;
   294→    }
   295→
   296→    this._logger.info('Barge-in accepted — interrupting response');
   297→
   298→    const current = this._context.currentTurn;
   299→    if (current) {
   300→      const interruption: TurnInterruption = {
   301→        detectedAt: now,
   302→        responseOffsetMs: current.responseStartedAt ? now - current.responseStartedAt : 0,
   303→      };
   304→      this._context.setCurrentTurn(recordInterruption(current, interruption));
   305→    }
   306→
   307→    await this._runtime.interrupt();
   308→    await this._session.interrupt();
   309→    this._interruptManager.acknowledge(now);
   310→
   311→    this._emit('orchestrator.interrupted', { turnIndex: this._turnIndex });
   312→
   313→    const interrupted = this._context.currentTurn;
   314→    if (interrupted) {
   315→      this._context.archiveTurn(interrupted, now);
   316→    }
   317→    this._interruptManager.clear();
   318→
   319→    await this._beginNextTurn();
   320→  }
   321→
   322→  getContext(): Readonly<ConversationContext> {
   323→    return this._context;
   324→  }
   325→
   326→  on(type: OrchestratorEventType, handler: OrchestratorEventHandler): void {
   327→    if (!this._handlers.has(type)) this._handlers.set(type, new Set());
   328→    this._handlers.get(type)!.add(handler);
   329→  }
   330→
   331→  off(type: OrchestratorEventType, handler: OrchestratorEventHandler): void {
   332→    this._handlers.get(type)?.delete(handler);
   333→  }
   334→
   335→  destroy(): void {
   336→    if (this._state === OrchestratorState.DESTROYED) return;
   337→    this._logger.info('ConversationOrchestrator destroying');
   338→    this._runtime.destroy();
   339→    this._session.close().catch(() => undefined);
   340→    this._setState(OrchestratorState.DESTROYED);
   341→    this._emit('orchestrator.destroyed', {});
   342→    this._handlers.clear();
   343→  }
   344→
   345→  // ─── Turn Lifecycle ──────────────────────────────────────────────────────
   346→
   347→  private async _beginNextTurn(): Promise<void> {
   348→    if (this._state !== OrchestratorState.RUNNING) return;
   349→
   350→    const now = this._clock.now();
   351→    const decision = this._scheduler.decide({
   352→      currentTurn: this._context.currentTurn,
   353→      previousTurn: this._context.previousTurn,
   354→      completedTurnCount: this._context.completedTurnCount,
   355→      interruptPending: this._interruptManager.isPending,
   356→      silenceTimeout: false,
   357→      responseTimeout: false,
   358→      sessionTimeout: false,
   359→      now,
   360→    });
   361→
   362→    this._logger.debug('Scheduling decision', { action: decision.action, reason: decision.reason });
   363→
   364→    if (decision.action === 'complete') {
   365→      await this.stop(decision.reason);
   366→      return;
   367→    }
   368→
   369→    if (decision.action === 'fail') {
   370→      this._setState(OrchestratorState.FAILED);
   371→      this._emit('orchestrator.failed', { reason: decision.reason });
   372→      return;
   373→    }
   374→
   375→    if (decision.action === 'start_listening') {
   376→      const turn = createTurn(
   377→        `turn_${this._nextTurnId++}`,
   378→        this._turnIndex++,
   379→        'user',
   380→        now
   381→      );
   382→      this._context.setCurrentTurn(turn);
   383→      this._emit('orchestrator.turn_started', { turnId: turn.turnId, turnIndex: turn.turnIndex });
   384→      await this._runtime.startListening();
   385→      this._context.setCurrentTurn(patchTurn(turn, { state: TurnState.LISTENING, listeningStartedAt: now }));
   386→    }
   387→  }
   388→
   389→  private async _onUtteranceCompleted(transcript: string): Promise<void> {
   390→    if (this._state !== OrchestratorState.RUNNING) return;
   391→    const now = this._clock.now();
   392→    let turn = this._context.currentTurn;
   393→    if (!turn) return;
   394→
   395→    turn = patchTurn(turn, {
   396→      state: TurnState.PROCESSING,
   397→      transcript,
   398→      utteranceCommittedAt: now,
   399→      latency: { ...turn.latency, sttLatencyMs: now - (turn.listeningStartedAt ?? now) },
   400→    });
   401→    this._context.setCurrentTurn(turn);
   402→    await this._runtime.startThinking(transcript);
   403→  }
   404→
   405→  private async _onResponseCompleted(response: string): Promise<void> {
   406→    if (this._state !== OrchestratorState.RUNNING) return;
   407→    const now = this._clock.now();
   408→    const turn = this._context.currentTurn;
   409→    if (!turn) return;
   410→
   411→    const completed = completeTurn(turn, response, now);
   412→    this._context.archiveTurn(completed, now);
   413→    this._emit('orchestrator.turn_completed', { turnId: turn.turnId, turnIndex: turn.turnIndex });
   414→
   415→    await this._beginNextTurn();
   416→  }
   417→
   418→  private async _onResponseStarted(responseId: string): Promise<void> {
   419→    if (this._state !== OrchestratorState.RUNNING) return;
   420→    const now = this._clock.now();
   421→    const turn = this._context.currentTurn;
   422→    if (!turn) return;
   423→
   424→    const withLatency = patchTurn(turn, {
   425→      state: TurnState.RESPONDING,
   426→      responseStartedAt: now,
   427→      latency: {
   428→        ...turn.latency,
   429→        llmLatencyMs: turn.utteranceCommittedAt ? now - turn.utteranceCommittedAt : null,
   430→      },
   431→    });
   432→    this._context.setCurrentTurn(withLatency);
   433→    await this._runtime.startSpeaking(responseId);
   434→  }
   435→
   436→  private async _onProviderError(message: string): Promise<void> {
   437→    const now = this._clock.now();
   438→    const turn = this._context.currentTurn;
   439→    if (turn) {
   440→      const failed = failTurn(turn, message, now);
   441→      this._context.archiveTurn(failed, now);
   442→      this._emit('orchestrator.turn_failed', { turnId: turn.turnId, reason: message });
   443→    }
   444→
   445→    const decision = this._scheduler.decide({
   446→      currentTurn: this._context.currentTurn,
   447→      previousTurn: this._context.previousTurn,
   448→      completedTurnCount: this._context.completedTurnCount,
   449→      interruptPending: false,
   450→      silenceTimeout: false,
   451→      responseTimeout: false,
   452→      sessionTimeout: false,
   453→      now,
   454→    });
   455→
   456→    if (decision.action === 'fail') {
   457→      this._setState(OrchestratorState.FAILED);
   458→      this._emit('orchestrator.failed', { reason: message });
   459→    } else {
   460→      await this._beginNextTurn();
   461→    }
   462→  }
   463→
   464→  // ─── Session Event Wiring ────────────────────────────────────────────────
   465→
   466→  private _registerSessionHandlers(): void {
   467→    this._session.on('realtime.transcript_completed', async (raw: unknown) => {
   468→      const event = raw as { transcript: string };
   469→      await this._onUtteranceCompleted(event.transcript ?? '').catch((err) => {
   470→        this._logger.error('Error handling transcript_completed', { error: String(err) });
   471→      });
   472→    });
   473→
   474→    this._session.on('realtime.response_started', async (raw: unknown) => {
   475→      const event = raw as { responseId: string };
   476→      await this._onResponseStarted(event.responseId ?? '').catch((err) => {
   477→        this._logger.error('Error handling response_started', { error: String(err) });
   478→      });
   479→    });
   480→
   481→    this._session.on('realtime.response_completed', async (raw: unknown) => {
   482→      const event = raw as { status: string; responseId: string };
   483→      if (event.status === 'completed') {
   484→        const turn = this._context.currentTurn;
   485→        await this._onResponseCompleted(turn?.response ?? '').catch((err) => {
   486→          this._logger.error('Error handling response_completed', { error: String(err) });
   487→        });
   488→      }
   489→    });
   490→
   491→    this._session.on('realtime.error', async (raw: unknown) => {
   492→      const event = raw as { message: string; fatal: boolean };
   493→      this._logger.error('Provider session error', { message: event.message, fatal: event.fatal });
   494→      if (event.fatal) {
   495→        await this._onProviderError(event.message).catch(() => undefined);
   496→      }
   497→    });
   498→  }
   499→
   500→  // ─── Private Helpers ─────────────────────────────────────────────────────
   501→
   502→  private _setState(state: OrchestratorState): void {
   503→    this._logger.debug('OrchestratorState', { from: this._state, to: state });
   504→    this._state = state;
   505→  }
   506→
   507→  private _assertState(expected: OrchestratorState, method: string): void {
   508→    if (this._state !== expected) {
   509→      throw new VoiceEngineError(
   510→        `ConversationOrchestrator.${method}() called in state ${this._state}, expected ${expected}`,
   511→        ErrorCode.PIPELINE_ABORTED,
   512→        false
   513→      );
   514→    }
   515→  }
   516→
   517→  private _emit(type: OrchestratorEventType, payload: Record<string, unknown>): void {
   518→    const event: OrchestratorEvent = {
   519→      type,
   520→      timestamp: this._clock.now(),
   521→      sessionId: this._context.sessionId,
   522→      payload: Object.freeze(payload),
   523→    };
   524→    const handlers = this._handlers.get(type);
   525→    if (!handlers) return;
   526→    Array.from(handlers).forEach((handler) => {
   527→      try { handler(event); } catch { /* swallow — event delivery must not crash the orchestrator */ }
   528→    });
   529→  }
   530→}
